const apikey = 'YOUR_SUPABASE_ANON_KEY';
const base  = 'https://bcibmmbxrjfiulofserv.supabase.co/rest/v1';
const hdr   = { apikey, Authorization: `Bearer ${apikey}` };

const now = new Date();
const centralStr = now.toLocaleDateString('en-CA', { timeZone: 'America/Chicago' });
const centralHour = Number(now.toLocaleString('en-US', { timeZone: 'America/Chicago', hour: 'numeric', hour12: false }));

const [snapshots, roster] = await Promise.all([
  this.helpers.httpRequest({
    method: 'GET',
    url: `${base}/intraday_snapshots?scrape_date=eq.${centralStr}&tier=eq.T3&order=scrape_hour.desc`,
    headers: hdr,
    json: true,
  }),
  this.helpers.httpRequest({
    method: 'GET',
    url: `${base}/agents?select=name,site&is_active=eq.true&tier=eq.T3`,
    headers: hdr,
    json: true,
  }),
]);

const siteMap = {};
for (const a of roster) siteMap[a.name] = a.site;

const latest = {};
for (const r of snapshots) {
  if (!latest[r.agent_name] && siteMap[r.agent_name]) {
    latest[r.agent_name] = r;
  }
}

return [{
  json: {
    scrapeDate: centralStr,
    centralHour,
    agents: Object.values(latest),
    siteMap,
  }
}];

const { scrapeDate, centralHour, agents, siteMap } = $input.first().json;

const PACE = { 9:0.05, 10:0.15, 11:0.28, 12:0.42, 13:0.50, 14:0.65, 15:0.78, 16:0.92, 17:1.0 };
const TGT  = { dials:200, talk:180, long:4, pool:50 };
const BEH  = 0.80;
function clamp(v,lo,hi){ return Math.min(Math.max(v,lo),hi); }

const results = [];
for (const row of agents) {
  const h = clamp(row.scrape_hour, 9, 17);
  const c = PACE[h] ?? 1.0;
  const mk = (act, tgt) => {
    const exp = Math.round(tgt * c);
    const pct = exp > 0 ? Math.round((act/exp)*100) : (act > 0 ? 100 : 0);
    return { actual: act, exp, pct, behind: act < exp * BEH };
  };
  const dials = mk(row.total_dials ?? 0, TGT.dials);
  const talk  = mk(row.talk_time_minutes ?? 0, TGT.talk);
  const long  = mk(row.pool_long_calls ?? 0, TGT.long);
  const pool  = mk(row.pool_dials ?? 0, TGT.pool);
  const behind = [];
  if (dials.behind) behind.push('Dials');
  if (talk.behind)  behind.push('Talk');
  if (long.behind)  behind.push('Long Calls');
  if (pool.behind)  behind.push('Pool');
  const status = behind.length >= 3 ? 'critical' : behind.length > 0 ? 'behind' : 'on_pace';
  const mpd = dials.actual > 0 ? talk.actual / dials.actual : 0;
  results.push({ name: row.agent_name, site: siteMap[row.agent_name]||'—', hour: row.scrape_hour, status, behind, dials, talk, long, pool, mpd });
}

const rnk = { critical:0, behind:1, on_pace:2 };
results.sort((a,b) => {
  if (rnk[a.status] !== rnk[b.status]) return rnk[a.status] - rnk[b.status];
  return b.behind.length - a.behind.length || a.dials.pct - b.dials.pct;
});

// ── Coaching insight engine ─────────────────────────────────────────
function insight(a) {
  const mpd = a.mpd.toFixed(1);
  if (a.dials.pct >= 70 && a.talk.pct < 40)
    return `${mpd} min/dial — dialing without engaging. Slow down, qualify, and present.`;
  if (a.dials.pct < 50 && a.talk.pct < 50)
    return `Only ${a.dials.actual} dials so far. Activity gap — needs to ramp up immediately.`;
  if (a.pool.actual > 0 && a.long.actual === 0 && a.pool.pct >= 80)
    return `${a.pool.actual} pool dials but 0 long calls. Dialing pool without presenting — qualify deeper.`;
  if (a.dials.pct >= 60 && a.talk.pct < 60)
    return `${mpd} min/dial — calls are too short. Focus on getting into presentations.`;
  if (a.dials.pct < 70 && a.talk.pct >= 60)
    return `Good engagement (${mpd} min/dial) but only ${a.dials.actual} dials. Need more volume.`;
  if (!a.dials.behind && a.talk.behind)
    return `Dials on track but talk time lagging — conversations ending too quickly.`;
  if (!a.dials.behind && !a.talk.behind && a.long.behind)
    return `Volume and talk OK but only ${a.long.actual} long calls. Push for 15+ min presentations.`;
  return `Behind on ${a.behind.join(' and ')}. Review activity and adjust.`;
}

const onP = results.filter(a => a.status==='on_pace').length;
const beh = results.filter(a => a.status==='behind').length;
const cri = results.filter(a => a.status==='critical').length;

const [y,mo,d] = scrapeDate.split('-');
const dt = new Date(+y, +mo-1, +d);
const dn = ['Sun','Mon','Tue','Wed','Thu','Fri','Sat'][dt.getDay()];
const mn = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'][dt.getMonth()];
const dd = `${dn} ${mn} ${+d}, ${y}`;
const ch = clamp(centralHour, 9, 17);
const cp = Math.round((PACE[ch]??1)*100);
const eD = Math.round(TGT.dials*(PACE[ch]??1));
const eT = Math.round(TGT.talk*(PACE[ch]??1));
const eL = Math.round(TGT.long*(PACE[ch]??1));
const eP = Math.round(TGT.pool*(PACE[ch]??1));

const blocks = [];

blocks.push({ type:'header', text:{ type:'plain_text', text:`Midday Pace Check — ${dd}` }});

blocks.push({ type:'section', text:{ type:'mrkdwn', text:
  `*${cp}% of day complete*  ·  ${centralHour > 12 ? centralHour - 12 : centralHour}:06 PM CT\n\n` +
  `By now each agent should have:\n` +
  `>  *${eD}* dials  ·  *${eT}m* talk  ·  *${eL}* long calls  ·  *${eP}* pool dials\n\n` +
  (results.length === 0 ? '_No T3 intraday data for today._'
    : `*${onP}* on pace  ·  *${beh}* behind  ·  *${cri}* need attention`)
}});

blocks.push({ type:'divider' });

const st = (lbl,m) => m.behind ? `*${lbl}: ${Math.round(m.actual)}/${m.exp}*` : `${lbl}: ${Math.round(m.actual)}/${m.exp}`;

const att = results.filter(a => a.status !== 'on_pace');
const pace = results.filter(a => a.status === 'on_pace');

for (const a of att) {
  const tag = a.status === 'critical' ? 'CRITICAL' : 'BEHIND';
  blocks.push({ type:'section', text:{ type:'mrkdwn', text:
    `*${tag}* — *${a.name}*  _(${a.site})_\n` +
    `${st('Dials',a.dials)}  ·  ${st('Talk',a.talk)}  ·  ${st('Long',a.long)}  ·  ${st('Pool',a.pool)}\n` +
    `_↳ ${insight(a)}_`
  }});
  if (blocks.length >= 46) {
    const rem = att.length - att.indexOf(a) - 1;
    if (rem > 0) blocks.push({ type:'section', text:{ type:'mrkdwn', text:`_…and ${rem} more behind pace._` }});
    break;
  }
}

if (att.length > 0 && pace.length > 0) blocks.push({ type:'divider' });

for (const a of pace) {
  blocks.push({ type:'section', text:{ type:'mrkdwn', text:
    `*${a.name}*  _(${a.site})_ — on pace\n` +
    `Dials: ${Math.round(a.dials.actual)}/${a.dials.exp}  ·  Talk: ${Math.round(a.talk.actual)}m/${a.talk.exp}m  ·  Long: ${a.long.actual}/${a.long.exp}  ·  Pool: ${Math.round(a.pool.actual)}/${a.pool.exp}`
  }});
  if (blocks.length >= 48) {
    const rem = pace.length - pace.indexOf(a) - 1;
    if (rem > 0) blocks.push({ type:'context', elements:[{ type:'mrkdwn', text:`_…and ${rem} more on pace._` }]});
    break;
  }
}

blocks.push({ type:'context', elements:[{ type:'mrkdwn',
  text:`Targets: 200 dials · 180m talk · 4 long calls · 50 pool dials  |  Behind = <80% of expected  |  5/7 gates = good standing`
}]});

const fallback = `Midday Pace Check — ${dd}: ${onP} on pace, ${beh} behind, ${cri} critical`;
return [{ json: { channel:'YOUR_SLACK_CHANNEL_ID', text: fallback, blocks } }];

return [{ json: {
  text: ':x: *Midday Pace Alert failed*\n' + ($input.first().json.error || 'Unknown error — check n8n execution log.')
} }];
